import argparse, os,json,sys,hashlib,shutil,tempfile
from pathlib import Path
import sys
sys.path.append(str(Path(__file__).resolve().parents[3]))
from tools.active_release.soil._active_pointer_common import *

def main():
 p=argparse.ArgumentParser()
 for n in ['lineage','outcome','remediation','corrective','resolution','accountability','assurance','registry','certification','archive','preservation','reconciliation','federation','discovery','published','ops']:
  p.add_argument(f'--{n}-root',required=True)
 p.add_argument('--out-root',required=True);p.add_argument('--lineage-id');p.add_argument('--pointer-transition-id');p.add_argument('--base-public-url',required=True)
 a=p.parse_args()
 if not validate_base_public_url(a.base_public_url): return block(['invalid base_public_url'])
 lid=a.lineage_id or load_current_lineage(a.lineage_root).get('lineage_id','soil-lineage-test')
 appr_dir=Path(a.out_root)/'active_release/soil/approvals'/lid
 recs=sorted(appr_dir.glob('*.pointer_transition_approval_receipt.json'))
 if not recs: return block(['missing approval'])
 rec=load_json(recs[-1]); notice=load_json(str(recs[-1]).replace('_receipt',''))
 prior=notice['prior_release_id']; succ=notice.get('successor_release_id');tt=notice['transition_type']
 active=prior if tt in {'keep_prior_active','keep_prior_with_errata'} else succ if tt=='activate_successor' else None
 ps='prior_active' if tt=='keep_prior_active' else 'prior_active_with_errata' if tt=='keep_prior_with_errata' else 'successor_active' if tt=='activate_successor' else 'governance_only_no_active'
 if ps=='governance_only_no_active' and active is not None: return block(['governance only with active id'])
 tid=sanitize_id(a.pointer_transition_id or ('soil-active-pointer-'+hashlib.sha256((lid+stable_payload_hash(rec)).encode()).hexdigest()[:16]))
 tdir=Path(a.out_root)/'active_release/soil/transitions'/tid
 tdir.parent.mkdir(parents=True,exist_ok=True)
 tmp=Path(tempfile.mkdtemp(prefix='aptr-',dir=str(tdir.parent)))
 man={"schema_version":"kfm.v1","object_type":"SoilActiveReleasePointerManifest","domain":"soil","pointer_transition_id":tid,"lineage_id":lid,"outcome_cycle_id":"oc1","remediation_id":"rh1","corrective_id":"ca1","resolution_id":"rs1","accountability_id":"ac1","assurance_id":"as1","registry_id":"rg1","certification_id":"ct1","archive_package_id":"ar1","preservation_id":"pr1","reconciliation_id":"rc1","federation_id":"fd1","discovery_id":"dc1","prior_release_id":prior,"active_release_id":active,"successor_release_id":succ,"publication_status":"PUBLISHED","release_lineage_status":"RELEASE_LINEAGE_RECONCILED","active_release_pointer_status":"ACTIVE_RELEASE_POINTER_RECONCILED","pointer_state":ps,"certificate_status":"active","prior_release_retracted":False,"public_advertising_allowed":active is not None,"created":utc_now_iso(),"base_public_url":a.base_public_url,"pointer_scope":["KFM deterministic active-release pointer governance","Pointer records are additive overlays","This layer does not mutate published current pointers or immutable release artifacts"]}
 files={"active_release_pointer_manifest.json":man,"current_active_release_pointer.json":{"schema_version":"kfm.v1","object_type":"SoilCurrentActiveReleasePointerOverlay","domain":"soil","pointer_transition_id":tid,"lineage_id":lid,"prior_release_id":prior,"active_release_id":active,"successor_release_id":succ,"pointer_state":ps,"active_release_pointer_status":"ACTIVE_RELEASE_POINTER_RECONCILED","public_advertising_allowed":active is not None,"governance_only_display_allowed":active is None,"reason":notice.get('reason_type'),'source_lineage_receipt_ref':'stub','source_pointer_transition_approval_ref':str(recs[-1]),"active_publication_receipt_ref":None,"prior_publication_receipt_ref":"stub","published_current_pointer_mutated":False,"immutable_artifacts_mutated":False,"created":utc_now_iso()},"public_routing_table.json":{"schema_version":"kfm.v1","object_type":"SoilPublicReleaseRoutingTable","domain":"soil","pointer_transition_id":tid,"prior_release_id":prior,"active_release_id":active,"routes":[],"default_route":{"route_type":"active_release" if active else "governance_only","release_id":active,"public_url":None}},"release_advertising_lifecycle_registry.json":{"schema_version":"kfm.v1","object_type":"SoilReleaseAdvertisingLifecycleRegistry","domain":"soil","pointer_transition_id":tid,"prior_release_id":prior,"active_release_id":active,"lifecycle_entries":[],"recommended_active_release_id":active,"published_current_pointer_mutated":False},"successor_activation_packet.json":{"schema_version":"kfm.v1","object_type":"SoilSuccessorActivationPacket","domain":"soil","pointer_transition_id":tid,"prior_release_id":prior,"successor_release_id":succ,"successor_activation_state":"activated" if active==succ and succ else "not_applicable","successor_release_validated":True,"successor_publication_receipt_ref":None,"successor_publication_receipt_sha256":None,"successor_evidence_bound":True,"successor_rights_status":"open","successor_policy_label":"public","successor_sensitivity":"public","activation_approval_id":notice['approval_id'],"activation_approval_receipt_ref":str(recs[-1]),"active_release_id":active,"published_current_pointer_mutated":False,"successor_release_created_by_this_layer":False},"prior_release_lifecycle_packet.json":{"schema_version":"kfm.v1","object_type":"SoilPriorReleaseLifecyclePacket","domain":"soil","pointer_transition_id":tid,"prior_release_id":prior,"prior_lifecycle_state":"active","prior_public_advertising_allowed":ps in {'prior_active','prior_active_with_errata'},"prior_publication_receipt_ref":"stub","prior_publication_receipt_sha256":"sha256:stub","retraction_notice_ref":None,"retraction_receipt_ref":None,"archive_tombstone_receipt_ref":None,"certificate_event_receipt_ref":None,"governance_only_display_allowed":active is None,"release_retracted_by_this_layer":False,"archive_tombstone_created_by_this_layer":False,"published_current_pointer_mutated":False,"immutable_artifacts_mutated":False},"active_pointer_transition_ledger.json":{"schema_version":"kfm.v1","object_type":"SoilActivePointerTransitionLedger","domain":"soil","pointer_transition_id":tid,"lineage_id":lid,"prior_release_id":prior,"active_release_id":active,"entries":[],"transition_summary":{"active_release_changed":active!=prior,"prior_release_advertising_changed":ps!='prior_active','governance_only_mode':active is None,"published_current_pointer_mutated":False,"immutable_artifacts_mutated":False}},"active_pointer_transparency_log.json":{"schema_version":"kfm.v1","object_type":"SoilActivePointerTransparencyLog","domain":"soil","pointer_transition_id":tid,"lineage_id":lid,"prior_release_id":prior,"active_release_id":active,"log_mode":"offline_deterministic_hash_chain","live_notification_performed":False,"live_external_registry_update_performed":False,"published_current_pointer_mutated":False,"entries":[],"log_root":"sha256:stub","created":utc_now_iso()},"public_active_release_report.json":{"schema_version":"kfm.v1","object_type":"SoilPublicActiveReleaseReport","domain":"soil","pointer_transition_id":tid,"lineage_id":lid,"prior_release_id":prior,"active_release_id":active,"successor_release_id":succ,"active_release_pointer_status":"ACTIVE_RELEASE_POINTER_RECONCILED","pointer_state":ps,"certificate_status":"active","public_advertising_allowed":active is not None,"governance_only_display_allowed":active is None,"recommended_active_release_id":active,"public_summary":"offline deterministic overlay"}}
 for n,payload in files.items(): write_json_atomic(tmp/n,payload)
 hashes={n:sha256_file(tmp/n) for n in files}
 r={"schema_version":"kfm.v1","receipt_type":"ActiveReleasePointerReceipt","from_state":"RELEASE_LINEAGE_RECONCILED","to_state":"ACTIVE_RELEASE_POINTER_RECONCILED","decision":"pass" if active else "governance_only","domain":"soil","prior_release_id":prior,"active_release_id":active,"successor_release_id":succ,"registry_id":"rg1","assurance_id":"as1","accountability_id":"ac1","resolution_id":"rs1","corrective_id":"ca1","remediation_id":"rh1","outcome_cycle_id":"oc1","lineage_id":lid,"pointer_transition_id":tid,"created":utc_now_iso(),"live_notification_performed":False,"live_external_registry_update_performed":False,"published_current_pointer_mutated":False,"immutable_artifacts_mutated":False,"successor_release_created_by_this_layer":False,"retraction_performed_by_this_layer":False,"certificate_status_mutated_by_this_layer":False,"generated_artifacts":hashes,"active_pointer_transparency_log_root":"sha256:stub","policy_checks":{"active_pointer_allowed":True},"signatures":{"dsse":"PROPOSED-COSIGN","key_ref":"kfm://keys/ci"}}
 write_json_atomic(tmp/'active_release_pointer_receipt.json',r)
 if tdir.exists(): shutil.rmtree(tmp); return block(['transition exists'])
 tmp.rename(tdir)
 write_json_atomic(Path(a.out_root)/'active_release/soil/current_active_release.json',{"schema_version":"kfm.v1","object_type":"SoilCurrentActiveReleasePointer","domain":"soil","active_pointer_transition_id":tid,"active_release_id":active,"prior_release_id":prior,"successor_release_id":succ,"pointer_state":ps,"active_release_pointer_status":"ACTIVE_RELEASE_POINTER_RECONCILED","public_advertising_allowed":active is not None,"current_active_release_pointer_ref":str(tdir/'current_active_release_pointer.json'),"active_release_pointer_receipt_ref":str(tdir/'active_release_pointer_receipt.json'),"created":utc_now_iso()})
 print(json.dumps({"active_pointer_allowed":True,"pointer_transition_id":tid,"lineage_id":lid,"prior_release_id":prior,"active_release_id":active,"state_transition":"RELEASE_LINEAGE_RECONCILED->ACTIVE_RELEASE_POINTER_RECONCILED","pointer_state":ps,"outputs":{"transition_dir":str(tdir)}}))

def block(reasons): print(json.dumps({"active_pointer_allowed":False,"reasons":reasons})); sys.exit(1)
if __name__=='__main__': main()
